        max: Optional['types.LLMCacheMaxAggregateInput'] = None,
        having: Optional['types.LLMCacheScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.LLMCacheCountAggregateInput']] = None,
